mapper.select:
select distinct TBT.* from T_BUS_CARGO_INFO TBCI left join T_BUS_TRUST_CARGO TBTC on TBTC.CARGO_INFO_ID = TBCI.ID left join T_BUS_TRUST TBT on TBT.id = TBTC.TRUST_ID where TBT.id is not null and exists( select * from (
select #{tmp_id, jdbcType=BIGINT} as TMPID from dual
) a where a.TMPID = TBCI.ID )
